class Solution:
    def twoEggDrop(self, n):
        # Independent DP: dp[m][e] = max floors coverable with m moves and e eggs.
        # answer is smallest m with dp[m][2] >= n.
        m = 0
        while True:
            m += 1
            # with m moves and 2 eggs, coverage = m(m+1)//2
            cover = 0
            for i in range(1, m + 1):
                cover += i
            if cover >= n:
                return m

